code.perFrame:
zoom = 0.9999;
rot = 0;
dx = 0;
dy = 0;
sx = 0.9999;
sy = 1;
warp = 0.01;
cx = 0.5;
cy = 0.5;
dec_med = pow (0.9, 30/fps);;
dec_slow = pow (0.99, 30/fps);;
beat = max (max (bass, mid), treb);;
avg = avg*dec_slow + beat*(1-dec_slow);;
is_beat = ((beat) > (avg+peak)) * ((time) > (t0+.2));;
t0 = is_beat*time + (1-is_beat)*t0;;
peak = is_beat * beat + (1-is_beat)*peak*dec_med;;
index = (index + is_beat) %4;;
index2 = (index2 + is_beat*bnot(index))%4;;
monitor = index2;;
q20 = avg;;
q21 = beat;;
q22 = peak;;
q23 = index;;
q24 = is_beat;;
q26 = (bass + mid + treb)/16;;
k1 =  is_beat*bnot(index)*bnot(index2);;
p1 =  k1*(p1+1) + (1-k1)*p1;;
p2 = dec_med * p2+ (1-dec_med)*p1;;
p3 = dec_med * p3+ (1-dec_med)*p2;;
rott = p3 * 3.1416/4;;
pos = pos + q20/140;;
q28 = pos;;
q27 = index+1;;
q1 = cos(rott);;
q2 = sin(rott);;
q3 = -q2;;
q4 = q1;;
trel = time/10;;
q5 = cos(trel);;
q6 = sin(trel);;
q7 = -q6;;
q8 = q5;;
trig = q24 * (index%4);;
mox = bnot(trig)*mox + trig * (rand (100)/100-.5);;
moy = bnot(trig)*moy + trig * (rand (100)/100-.5);;
q15 = mox/2;;
q16 = moy/2;;
//speed;
speed = speed * bnot(trig) + trig * q26;;
movz = movz + speed/fps;;
q9 = movz;;
q30 = (1.2 + sin(time/7))*3;;
zoom = 1;;
rot = -0.00;
